const body=$input.first().json.body||$input.first().json;
const db06_id=(body.db06_id||body.id||'').toString().replace(/-/g,'');
if(!db06_id) throw new Error('missing db06_id');
return [{ json:{ db06_id } }];

const p=$input.first().json;
const T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"];
let target_id='',target_rel='';
for(const r of T){const a=p.properties[r]?.relation||[]; if(a.length){target_id=(a[0].id||'').replace(/-/g,'');target_rel=r;break;}}
return [{ json:{
  db06_id:p.id.replace(/-/g,''),
  ai_mode:p.properties['ai模式']?.select?.name||'聯想',
  exec_idea:p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('')||'',
  db05_id:target_id, target_rel,
  sort_num:p.properties['排序']?.number
}}];

const target=$input.first().json;
const item=$('Parse DB06').first().json;
const tp=target.properties||{};
const _t=Object.values(tp).find(v=>v&&v.type==='title');
const target_name=(_t?.title||[]).map(t=>t.plain_text).join('')||'(未命名)';
const target_idea=tp['執行構想']?.rich_text?.map(t=>t.plain_text).join('')||'';
let files=[];
for(const k of Object.keys(tp)){ const v=tp[k]; if(v&&v.type==='files'&&Array.isArray(v.files)){ for(const f of v.files){ const url=f.file?.url||f.external?.url; if(url) files.push({name:f.name||'',url}); } } }
const pdf=files.find(f=>/\.pdf(\?|$)/i.test(f.url)||/\.pdf$/i.test(f.name))||files[0]||null;
return [{ json:{ ...item, target_name, target_idea, pdf_url: pdf?pdf.url:'', pdf_name: pdf?pdf.name:'' } }];

const j=$input.first().json;
let pdf_b64='',pdf_ok=false;
if(j.pdf_url){ try{ const buf=await this.helpers.httpRequest({url:j.pdf_url,encoding:'arraybuffer'}); pdf_b64=Buffer.from(buf).toString('base64'); pdf_ok=pdf_b64.length>0; }catch(e){ pdf_ok=false; } }
const system='你是 makesense（現思文化）嗨嗨家族的聯想棒。職責:讀本案的附件文件與脈絡,做關聯聯想。
工作:
1. 通讀附件 PDF,提煉與本案直接相關的關鍵構想,尤其各樓層/分區/分期的規劃內容。
2. 指出本案可關聯、可引用的方向(哪類既有資料、哪些主題值得連)。
3. 寫一段聯想結果:這份文件對本案(經費估算)的啟示。
鐵律:只根據文件與脈絡寫,不臆測;繁體中文。
只回合法 JSON:
{"聯想結果":"200-500字","樓層規劃要點":["樓層=規劃重點"],"關聯建議":["..."],"execution_summary":"做了什麼"}';
const userText='target 內容
名稱 '+j.target_name+'
本棒執行構想
'+(j.exec_idea||j.target_idea||'(空)')+'

'+(pdf_ok?('附件 PDF「'+j.pdf_name+'」已附上,請通讀。'):'(本案讀不到 PDF 附件,僅依上述脈絡聯想)')+'

請依執行構想做聯想,回 JSON。';
const content=[];
if(pdf_ok) content.push({type:'document',source:{type:'base64',media_type:'application/pdf',data:pdf_b64}});
content.push({type:'text',text:userText});
const claude_body={ model:'claude-haiku-4-5-20251001', max_tokens:4096, system, messages:[{role:'user',content}] };
return [{ json:{ claude_body, db06_id:j.db06_id, db05_id:j.db05_id, ai_mode:j.ai_mode, sort_num:j.sort_num, pdf_ok, pdf_name:j.pdf_name } }];

const resp=$input.first().json;
const text=resp.content?.[0]?.text||'';
const usage=resp.usage||{};
const prompt=$('Download PDF + build body').first().json;
let parsed;
try{ const m=text.match(/\{[\s\S]*\}/); parsed=m?JSON.parse(m[0]):{'聯想結果':text.slice(0,500)}; }
catch(e){ parsed={'聯想結果':'JSON parse failed: '+text.slice(0,300)}; }
const sanitize=s=>(s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/[\u2010-\u2027\u2030-\u205E]/g,' ').replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g,' ').replace(/[\u3000-\u3017\u301D-\u303F]/g,' ').replace(/\s+/g,' ').trim().slice(0,600);
const it=parseInt(usage.input_tokens||0),ot=parseInt(usage.output_tokens||0);
const cost=((it*3+ot*15)/1000000*32).toFixed(2);
const usage_line='進='+it+' 出='+ot+' 成本NT'+cost;
const lx=(parsed['聯想結果']||'').toString();
const floors=Array.isArray(parsed['樓層規劃要點'])?parsed['樓層規劃要點']:[];
const links=Array.isArray(parsed['關聯建議'])?parsed['關聯建議']:[];
let full=lx;
if(floors.length) full+='\n\n[樓層規劃要點]\n- '+floors.join('\n- ');
if(links.length) full+='\n\n[關聯建議] '+links.join('；');
full=full.slice(0,1900);
const summary=(parsed['execution_summary']||'聯想完成')+(prompt.pdf_ok?' 已讀附件 '+prompt.pdf_name:' (無 PDF)')+' 樓層要點 '+floors.length+' 項 關聯建議 '+links.length+' 項';
return [{ json:{ db06_id:prompt.db06_id, db05_id:prompt.db05_id, ai_mode:prompt.ai_mode, sort_num:prompt.sort_num, lianxiang_full:full, usage_line, safe_summary:sanitize(summary), preview_text:('聯想結果已寫入 '+full.length+' 字'), validator_warning:'' } }];

const row = $input.first().json || {};
const pc = $('Parse Claude').first().json;
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const base = '關卡B 成果確認
第 ' + (pc.sort_num != null ? pc.sort_num : '?') + ' 棒 (' + pc.ai_mode + ') 已完成。
DB06 頁面 ' + pc.db06_id + '

執行備註:
' + pc.safe_summary + '

' + pc.preview_text + (pc.validator_warning || '') + '
tokens ' + pc.usage_line;
const manual_msg = base + '

按 OK 進下一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。
gateB db06=' + pc.db06_id;
const auto_msg = base + '

[全自動模式] 自動進下一棒,免按。';
return [{ json: { auto_mode, reply_to, flow_id: pc.db05_id, db05_id: pc.db05_id, db06_id: pc.db06_id, sort_num: pc.sort_num, ai_mode: pc.ai_mode, manual_msg, auto_msg, cb_ok: 'B1:' + pc.db06_id, cb_all: 'BA:' + pc.db06_id } }];

